document.addEventListener("DOMContentLoaded", () => {
setupMobileMenu();
setupTheme();
setupLanguage();
loadArticleDetails();
setupShareBubble();
});
function setupMobileMenu() {
const hamburger = document.getElementById("hamburger");
const navMenu = document.getElementById("navMenu");
const navLinks = document.querySelectorAll(".nav-link");
if (hamburger && navMenu) {
hamburger.addEventListener("click", () => {
hamburger.classList.toggle("open");
navMenu.classList.toggle("open");
});
navLinks.forEach(link => {
link.addEventListener("click", () => {
hamburger.classList.remove("open");
navMenu.classList.remove("open");
});
});
}
}
function setupTheme() {
const themeToggleBtn = document.getElementById("themeToggle");
const currentTheme = localStorage.getItem("theme");
if (currentTheme === "light") {
document.body.classList.add("light-mode");
}
if (themeToggleBtn) {
themeToggleBtn.addEventListener("click", () => {
document.body.classList.toggle("light-mode");
const theme = document.body.classList.contains("light-mode") ? "light" : "dark";
localStorage.setItem("theme", theme);
});
}
}
function setupLanguage() {
const langSelect = document.getElementById("langSelect");
let currentLang = localStorage.getItem("language") || "tr";
if (langSelect) {
langSelect.value = currentLang;
langSelect.addEventListener("change", (e) => {
const selectedLang = e.target.value;
localStorage.setItem("language", selectedLang);
updatePageLanguage(selectedLang);
document.documentElement.lang = selectedLang;
loadArticleDetails();
});
}
updatePageLanguage(currentLang);
}
function updatePageLanguage(lang) {
const translatableElements = document.querySelectorAll("[data-i18n]");
translatableElements.forEach(element => {
const key = element.getAttribute("data-i18n");
if (translations[key] && translations[key][lang]) {
element.textContent = translations[key][lang];
}
});
}
function loadArticleDetails() {
const params = new URLSearchParams(window.location.search);
const articleId = parseInt(params.get("id")) || 1;
const lang = localStorage.getItem("language") || "tr";
const article = articlesDetailedDb[articleId] || articlesDetailedDb[1];
const breadcrumbSpan = document.getElementById("ndBreadcrumbCurrent");
const articleTitle = document.getElementById("ndArticleTitle");
const articleDate = document.getElementById("ndArticleDate");
const articleCategory = document.getElementById("ndArticleCategory");
const featuredImg = document.getElementById("ndFeaturedImg");
const introText = document.getElementById("ndArticleIntro");
const contentBody = document.getElementById("ndArticleContent");
const quoteBody = document.getElementById("ndArticleQuote");
const attachmentsList = document.getElementById("ndAttachmentsList");
if (breadcrumbSpan) {
breadcrumbSpan.textContent = lang === "tr" ? article.titleTR : article.titleEN;
}
if (articleTitle) {
articleTitle.textContent = lang === "tr" ? article.titleTR : article.titleEN;
}
if (articleDate) {
articleDate.textContent = lang === "tr" ? article.dateTextTR : article.dateTextEN;
}
if (articleCategory) {
articleCategory.textContent = lang === "tr" ? article.categoryTR : article.categoryEN;
articleCategory.className = "meta-category badge-category";
if (article.category === "drone") {
articleCategory.classList.add("badge-drone");
} else if (article.category === "academy") {
articleCategory.classList.add("badge-academy");
} else if (article.category === "aviation") {
articleCategory.classList.add("badge-aviation");
}
}
if (featuredImg) {
featuredImg.src = article.imgUrl;
featuredImg.alt = lang === "tr" ? article.titleTR : article.titleEN;
}
if (introText) {
introText.textContent = lang === "tr" ? article.introTR : article.introEN;
}
if (contentBody) {
contentBody.innerHTML = lang === "tr" ? article.contentTR : article.contentEN;
}
if (quoteBody) {
quoteBody.textContent = lang === "tr" ? article.quoteTR : article.quoteEN;
}
if (attachmentsList) {
let attachmentsHtml = "";
const downloadLabel = translations["nd_download_btn"][lang];
article.attachments.forEach(file => {
let fileIconSvg = "";
if (file.type === "pdf") {
fileIconSvg = `
<svg viewBox="0 0 24 24" class="file-svg-icon is-pdf">
<path fill="currentColor" d="M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm-9 14H8.5v-1.5H7v-1h1.5V13H7v-1h3v5zm5 0h-3V12h3c.55 0 1 .45 1 1v3c0 .55-.45 1-1 1zm-4-1.5h1.5v-2H11v2zm5-1.5h-1v1h1v-1z"/>
</svg>
`;
} else {
fileIconSvg = `
<svg viewBox="0 0 24 24" class="file-svg-icon is-doc">
<path fill="currentColor" d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/>
</svg>
`;
}
attachmentsHtml += `
<div class="attachment-row">
<div class="attachment-file-info">
${fileIconSvg}
<div class="file-details">
<span class="file-name" title="${file.name}">${file.name}</span>
<span class="file-size">${file.size}</span>
</div>
</div>
<button class="attachment-download-btn" onclick="handleFileDownload('${file.name}')">
<svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
<path d="M19.35 10.04C18.67 6.59 15.64 4 12 4 9.11 4 6.6 5.64 5.35 8.04 2.34 8.36 0 10.91 0 14c0 3.31 2.69 6 6 6h13c2.76 0 5-2.24 5-5 0-2.64-2.05-4.78-4.65-4.96zM17 13l-5 5-5-5h3V9h4v4h3z"/>
</svg>
<span>${downloadLabel}</span>
</button>
</div>
`;
});
attachmentsList.innerHTML = attachmentsHtml;
}
const pageUrl = encodeURIComponent(window.location.href);
const pageTitleText = encodeURIComponent(lang === "tr" ? article.titleTR : article.titleEN);
const shareWA = document.getElementById("shareWA");
const shareLI = document.getElementById("shareLI");
if (shareWA) {
shareWA.href = `https://api.whatsapp.com/send?text=${pageTitleText}%20-%20${pageUrl}`;
shareWA.target = "_blank";
shareWA.rel = "noopener noreferrer";
}
if (shareLI) {
shareLI.href = `https://www.linkedin.com/sharing/share-offsite/?url=${pageUrl}`;
shareLI.target = "_blank";
shareLI.rel = "noopener noreferrer";
}
}
function setupShareBubble() {
const toggleBtn = document.getElementById("shareBubbleToggle");
const wrapper = document.getElementById("shareBubbleWrapper");
if (toggleBtn && wrapper) {
toggleBtn.addEventListener("click", (e) => {
e.stopPropagation();
wrapper.classList.toggle("open");
});
document.addEventListener("click", () => {
wrapper.classList.remove("open");
});
const popover = document.getElementById("shareBubblePopover");
if (popover) {
popover.addEventListener("click", (e) => {
e.stopPropagation();
});
}
}
}
function handleFileDownload(fileName) {
alert(`"${fileName}" dosyası indirilmeye başlandı (MOCK DOWNLOAD).`);
}
window.handleFileDownload = handleFileDownload;